// Check each token against each spender
let loggedFirst = false
for (const tokenAddress of tokenAddressSet) {
  const metadata = tokenMetadata.get(tokenAddress)
  const tokenSymbol = metadata?.symbol || tokenAddress.slice(0, 8)

  for (const spender of spendersToCheck) {
    try {
      checkedCount++

      const currentAllowance = await publicClient.readContract({
        address: tokenAddress as `0x${string}`,
        abi: [{
          name: 'allowance',
          type: 'function',
          stateMutability: 'view',
          inputs: [
            { name: 'owner', type: 'address' },
            { name: 'spender', type: 'address' }
          ],
          outputs: [{ name: 'remaining', type: 'uint256' }],
        }],
        functionName: 'allowance',
        args: [address as `0x${string}`, spender.address as `0x${string}`],
      })

      // Log first few checks to debug
      if (!loggedFirst && checkedCount <= 3) {
        console.log(`Check ${checkedCount}: ${tokenSymbol} (${tokenAddress}) → ${spender.name} (${spender.address})`)
        console.log(`  Owner: ${address}`)
        console.log(`  Allowance result: ${currentAllowance.toString()}`)
        if (checkedCount === 3) loggedFirst = true
      }

      if (currentAllowance > 0n) {
        const maxUint256 = BigInt('0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff')
        const isUnlimited = currentAllowance >= maxUint256 / 2n

        const token = metadata || {
          address: tokenAddress,
          symbol: 'UNKNOWN',
          name: tokenAddress,
          decimals: 18,
          chainId: revokeChain.id,
        }

        console.log(`✅ FOUND APPROVAL: ${token.symbol} → ${spender.name}`)
        console.log(`   Allowance: ${currentAllowance.toString()}`)

        foundApprovals.push({
          token,
          spender: spender.address,
          spenderName: spender.name,
          allowance: currentAllowance.toString(),
          allowanceFormatted: isUnlimited ? 'Unlimited' : formatUnits(currentAllowance, token.decimals),
          riskLevel: isUnlimited ? 'high' : 'low',
        })
      }
    } catch (e) {
      if (checkedCount <= 3) {
        console.error(`Error on check ${checkedCount}:`, e)
      }
    }

    if (checkedCount % 20 === 0) {
      await new Promise(resolve => setTimeout(resolve, 100))
    }
  }
}
